// Generate unique email per test run to avoid collisions with existing data
const testEmail = `e2e-${Date.now()}@example.com`;
const testPassword = "securepassword123";

test.describe("Core user journey", () => {
  test("visitor sees register and sign in links on index page", async ({
    page,
  }) => {
    await page.goto("/");

    await expect(page).toHaveTitle("Todo List");
    await expect(
      page.getByRole("heading", { name: "Welcome" })
    ).toBeVisible();
    await expect(
      page.getByRole("link", { name: "Create account" }).first()
    ).toBeVisible();
    await expect(
      page.getByRole("link", { name: "Sign in" }).first()
    ).toBeVisible();
  });

  test("full user journey: register, add, complete, delete, logout", async ({
    page,
  }) => {
    // 1. Visit index and click Create account
    await page.goto("/");
    await page
      .getByRole("link", { name: "Create account" })
      .first()
      .click();
    await expect(page).toHaveURL(/\/register/);

    // 2. Fill registration form and submit
    // The password-toggle.js may remove the confirm field when JS is active.
    // Fill password fields first, then handle confirm if still visible.
    await page.getByLabel("Email").fill(testEmail);
    await page.getByLabel("Password", { exact: true }).fill(testPassword);
    const confirmField = page.getByLabel("Confirm password");
    if (await confirmField.isVisible({ timeout: 500 }).catch(() => false)) {
      await confirmField.fill(testPassword);
    }
    await page.getByRole("button", { name: "Create account" }).click();

    // Should redirect to login after registration
    await expect(page).toHaveURL(/\/login/);

    // 3. Log in
    await page.getByLabel("Email").fill(testEmail);
    await page.getByLabel("Password").fill(testPassword);
    await page.getByRole("button", { name: "Sign in" }).click();

    // Should redirect to todos
    await expect(page).toHaveURL(/\/todos/);
    await expect(
      page.getByRole("heading", { name: "My Todos" })
    ).toBeVisible();

    // 4. Add a todo
    await page.getByLabel("New todo").fill("Buy groceries");
    await page.getByRole("button", { name: "Add todo" }).click();

    // The todo should appear in the list
    await expect(page.getByText("Buy groceries")).toBeVisible();

    // 5. Complete the todo (click the toggle button)
    await page
      .getByRole("button", { name: /Mark .+Buy groceries.+ as complete/ })
      .click();

    // After toggling, the page should still show the todo
    // (either via HTMX swap or page reload)
    await expect(page.getByText("Buy groceries")).toBeVisible();

    // 6. Delete the todo
    // The delete uses a <details>/<summary> confirmation pattern
    // The summary element has aria-label='Delete "Buy groceries"'
    await page.locator('[aria-label*="Delete"][aria-label*="Buy groceries"]').click();
    // Click the confirm delete button
    await page.getByRole("button", { name: "Yes" }).click();

    // The todo should be removed
    await expect(page.getByText("Buy groceries")).not.toBeVisible();

    // 7. Logout
    await page.getByRole("button", { name: "Sign out" }).click();

    // Should redirect to login, then we go to index
    await page.goto("/");
    await expect(
      page.getByRole("link", { name: "Create account" }).first()
    ).toBeVisible();
    await expect(
      page.getByRole("link", { name: "Sign in" }).first()
    ).toBeVisible();
  });

  test("authenticated user is redirected from index to todos", async ({
    page,
  }) => {
    const email = `e2e-redirect-${Date.now()}@example.com`;

    // Register -- the password-toggle.js may remove the confirm field,
    // so fill password fields before the JS runs, or handle both cases.
    await page.goto("/register");
    await page.getByLabel("Email").fill(email);
    await page.getByLabel("Password", { exact: true }).fill(testPassword);

    // The JS progressive enhancement may have removed the confirm field.
    // If visible, fill it; otherwise the hidden input mirrors password automatically.
    const confirmField = page.getByLabel("Confirm password");
    if (await confirmField.isVisible({ timeout: 500 }).catch(() => false)) {
      await confirmField.fill(testPassword);
    }

    await page.getByRole("button", { name: "Create account" }).click();

    // Login
    await page.goto("/login");
    await page.getByLabel("Email").fill(email);
    await page.getByLabel("Password").fill(testPassword);
    await page.getByRole("button", { name: "Sign in" }).click();
    await expect(page).toHaveURL(/\/todos/);

    // Now visit index -- should redirect to /todos
    await page.goto("/");
    await expect(page).toHaveURL(/\/todos/);
  });
});
